func TestEnumSex(t *testing.T) {
	t.Run("NewFromString_female", func(t *testing.T) {
		t.Parallel()
		val, err := NewSexFromString("female")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, Sex("female"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_male", func(t *testing.T) {
		t.Parallel()
		val, err := NewSexFromString("male")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, Sex("male"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_other", func(t *testing.T) {
		t.Parallel()
		val, err := NewSexFromString("other")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, Sex("other"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_Invalid", func(t *testing.T) {
		_, err := NewSexFromString("invalid_value_that_does_not_exist")
		assert.Error(t, err)
	})

	t.Run("Ptr", func(t *testing.T) {
		val, err := NewSexFromString("female")
		assert.NoError(t, err)
		ptr := val.Ptr()
		assert.NotNil(t, ptr)
		assert.Equal(t, val, *ptr)
	})
}

